previewCss:
.darma-loader-darma-custom-019 {
  width: 40px;
  aspect-ratio: .577;
  clip-path: polygon(0 0, 100% 100%, 0 100%, 100% 0);
  position: relative;
  animation: darma-loader-darma-custom-019-l19 2s infinite linear;
  overflow: hidden;
}
.darma-loader-darma-custom-019::before {
  content: "";
  position: absolute;
  inset: -150%;
  background: repeating-conic-gradient(from 30deg, var(--loader-color, #FFABAB) 0 60deg, var(--loader-secondary-color, #ABE4FF) 0 120deg, #FF7373 0 180deg);
  animation: inherit;
  animation-direction: reverse;
}
@keyframes darma-loader-darma-custom-019-l19 {
  100% { transform: rotate(360deg); }
}

